import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    String homepage;
    String author;
    List<String> contributors;
    List<String> keywords;
    String main;
    String jsnextMain;
    String typings;
    TypesVersions typesVersions;
    Engines engines;
    Repository repository;
    Bugs bugs;
    String license;
    DevDependencies devDependencies;
    String ender;
    String dojoBuild;
    Jspm jspm;
    Scripts scripts;
    Spm spm;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.homepage,
        required this.author,
        required this.contributors,
        required this.keywords,
        required this.main,
        required this.jsnextMain,
        required this.typings,
        required this.typesVersions,
        required this.engines,
        required this.repository,
        required this.bugs,
        required this.license,
        required this.devDependencies,
        required this.ender,
        required this.dojoBuild,
        required this.jspm,
        required this.scripts,
        required this.spm,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        homepage: json["homepage"],
        author: json["author"],
        contributors: List<String>.from(json["contributors"].map((x) => x)),
        keywords: List<String>.from(json["keywords"].map((x) => x)),
        main: json["main"],
        jsnextMain: json["jsnext:main"],
        typings: json["typings"],
        typesVersions: TypesVersions.fromJson(json["typesVersions"]),
        engines: Engines.fromJson(json["engines"]),
        repository: Repository.fromJson(json["repository"]),
        bugs: Bugs.fromJson(json["bugs"]),
        license: json["license"],
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
        ender: json["ender"],
        dojoBuild: json["dojoBuild"],
        jspm: Jspm.fromJson(json["jspm"]),
        scripts: Scripts.fromJson(json["scripts"]),
        spm: Spm.fromJson(json["spm"]),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "homepage": homepage,
        "author": author,
        "contributors": List<dynamic>.from(contributors.map((x) => x)),
        "keywords": List<dynamic>.from(keywords.map((x) => x)),
        "main": main,
        "jsnext:main": jsnextMain,
        "typings": typings,
        "typesVersions": typesVersions.toJson(),
        "engines": engines.toJson(),
        "repository": repository.toJson(),
        "bugs": bugs.toJson(),
        "license": license,
        "devDependencies": devDependencies.toJson(),
        "ender": ender,
        "dojoBuild": dojoBuild,
        "jspm": jspm.toJson(),
        "scripts": scripts.toJson(),
        "spm": spm.toJson(),
    };
}

class Bugs {
    String url;

    Bugs({
        required this.url,
    });

    factory Bugs.fromJson(Map<String, dynamic> json) => Bugs(
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "url": url,
    };
}

