    factory Jspm.fromJson(Map<String, dynamic> json) => Jspm(
        files: List<String>.from(json["files"].map((x) => x)),
        map: MapClass.fromJson(json["map"]),
        buildConfig: BuildConfig.fromJson(json["buildConfig"]),
