class The31 {
    List<String> empty;
    List<String> minMomentWithLocales;

    The31({
        required this.empty,
        required this.minMomentWithLocales,
    });

    factory The31.fromJson(Map<String, dynamic> json) => The31(
        empty: List<String>.from(json["*"].map((x) => x)),
        minMomentWithLocales: List<String>.from(json["min/moment-with-locales"].map((x) => x)),
    );

    Map<String, dynamic> toJson() => {
        "*": List<dynamic>.from(empty.map((x) => x)),
        "min/moment-with-locales": List<dynamic>.from(minMomentWithLocales.map((x) => x)),
    };
}
